INSERT INTO public.photos VALUES (23012, 'Miguel Indurain 1994', 'Foto: Guillermo Mestre. Fiestas del Pilar de 1994. Miguel Indurain (Villava, 1964), el ciclista espaâ”śâ–’ol con mejor palmarâ”śÂ®s de la historia, participa en la segunda ediciâ”śâ”‚n del Critâ”śÂ®rium Internacional Ciudad de Zaragoza. Ganâ”śâ”‚ Perico Delgado. Al fondo, la calle del Marquâ”śÂ®s de Casa Jimâ”śÂ®nez, en su emboque desde el paseo de la Independencia. Fuente: Heraldo de Aragâ”śâ”‚n.', 1994, 1994, 1994, 'Anos 90', 'CENTRO', 41.64963100, -0.88358600, '0101000020E6100000B682A6255646ECBFE0BBCD1B27D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33116891760.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33116891760.webp', 'https://www.flickr.com/photos/zaragozaantigua/33116891760/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23061, 'Fernando Escartâ”śÂˇn 1997', 'Imagen capturada durante la ceremonia de entrega de trofeos tras la celebraciâ”śâ”‚n del Critâ”śÂ®rium Fiestas del Pilar en su III Ediciâ”śâ”‚n. Recoge su reconocimiento como vencedor de la clasificaciâ”śâ”‚n general el ciclista oscense Fernando Escartâ”śÂˇn, que ya lo fue en la ediciâ”śâ”‚n de 1993, y lo serâ”śÂˇa en la de 1999. Esta prueba ciclista comenzâ”śâ”‚ a disputarse en 1993, y tenâ”śÂˇa como escenario el paseo de la Independencia. Hasta 2005 se celebraron diez de estas pruebas, que aâ”śâ–’os mâ”śĂ­s tarde se retomaron en otra ubicaciâ”śâ”‚n, otros patrocinadores y un carâ”śĂ­cter mâ”śĂ­s domâ”śÂ®stico, sin el glamur de la etapa anterior. En la imagen, Fernando Escartâ”śÂˇn recibe su premio con el preceptivo cachirulo y el fondo de la plaza de Santa Engracia.', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.64949000, -0.88335800, '0101000020E6100000751E15FF7744ECBF1E8A027D22D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50498040707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50498040707.webp', 'https://www.flickr.com/photos/zaragozaantigua/50498040707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23063, 'P.â”¬â•‘ de la Independencia 1997', 'Imagen capturada en el paseo/autopista de la Independencia durante la plantaciâ”śâ”‚n de arbustos en la fina medianera entre los carriles de bajada a la plaza de Espaâ”śâ–’a, con la intenciâ”śâ”‚n de convertirlo en un mini corredor verde o estrecha cinta de vegetaciâ”śâ”‚n en un ocâ”śÂ®ano de asfalto y vehâ”śÂˇculos. Durante esta operaciâ”śâ”‚n se inhabilitâ”śâ”‚ al trâ”śĂ­fico uno de los carriles, lo que aumentâ”śâ”‚ temporalmente el estrâ”śÂ®s circulatorio del centro urbano.', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.65055700, -0.88257500, '0101000020E6100000E78C28ED0D3EECBF8997A77345D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50510349661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50510349661.webp', 'https://www.flickr.com/photos/zaragozaantigua/50510349661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23179, 'P.â”¬â•‘ de la Independencia 2004', 'El 11 de marzo de 2004, una câ”śÂ®lula yihadista provocâ”śâ”‚ varias explosiones en trenes de cercanâ”śÂˇas de Madrid, falleciendo 193 personas y resultando heridas alrededor de 2.000. Al dâ”śÂˇa siguiente se convocaron manifestaciones de repulsa, mientras la versiâ”śâ”‚n oficial aseguraba la autorâ”śÂˇa de ETA. En Zaragoza se anunciâ”śâ”‚ la comparecencia de medio millâ”śâ”‚n de personas. En la imagen, la manifestaciâ”śâ”‚n, a su paso por el paseo de la Independencia, vista desde la plaza de Espaâ”śâ–’a. Fuente: Heraldo de Aragâ”śâ”‚n.', 2004, 2004, 2004, 'Siglo XXI', 'CENTRO', 41.65019900, -0.88332600, '0101000020E61000009D9B36E33444ECBF2A7288B839D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38335017061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38335017061.webp', 'https://www.flickr.com/photos/zaragozaantigua/38335017061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23238, 'Arrabal de Sinhaya 2002', 'Durante las obras para construir un aparcamiento subterrâ”śĂ­neo que se descartâ”śâ”‚ en el paseo de la Independencia de Zaragoza, aparecieron los restos de la barriada musulmana de los Sinhaya, tribus bereberes del norte de â”śĂĽfrica. Tambiâ”śÂ®n se encontraron trazas de una iglesia româ”śĂ­nica, quizâ”śĂ­s la primera construcciâ”śâ”‚n cristiana de la ciudad. En el Arrabal de Sinhaya se alzaba la mezquita de Abu Jalid, e incluâ”śÂˇa las actuales plaza de Salamero y calle del Azoque. El conjunto es de los siglos XI y XII, justo antes de que Alfonso I conquistara Medina Albaida Saraqusta, y con ella su barrio artesano, convertido en morerâ”śÂˇa. Fuente visual: ABC.', 2002, 2002, 2002, 'Siglo XXI', 'CENTRO', 41.65082100, -0.88225300, '0101000020E61000004C88B9A46A3BECBF67463F1A4ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14904366960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14904366960.webp', 'https://www.flickr.com/photos/zaragozaantigua/14904366960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23641, 'Calle Casa Jimâ”śÂ®nez 1925', 'AHPZ. Archivo fotogrâ”śĂ­fico Julio Requejo. 11/06/1925. "Gigantes y cabezudos." Desde la altura de uno de los edificios de viviendas de la â”śÂ®poca, imagen de la calle Marquâ”śÂ®s de Casa Jimâ”śÂ®nez en el momento en que pasa por ella la comparsa de Gigantes y Cabezudos. La verja de la izquierda pertenece al recinto del Gobierno Militar, instalado sobre el Convento de las Descalzas de San Josâ”śÂ®, allâ”śÂˇ situado desde el siglo XVI (con restos de la iglesia, el claustro, y las bodegas) que, tras las recientes alineaciones habâ”śÂˇa quedado localizado en una manzana delimitada por las calles de Albareda, Ponzano (a la izquierda) y la de Bilbao (al fondo, donde comienza el extenso Cuartel de Artillerâ”śÂˇa del Carmen). La calle de Casa Jimâ”śÂ®nez llegaba, haciendo curva hacia la derecha, hasta la denominada "Plaza del Pueblo" y la calle del Azoque.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64996300, -0.88445300, '0101000020E6100000BB2BBB60704DECBF164ED2FC31D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15402341555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15402341555.webp', 'https://www.flickr.com/photos/zaragozaantigua/15402341555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23960, 'El Petit Park 1917', 'AHPZ. Archivo Julio Requejo. 14/10/1917. "Fiesta de Jota en el Petit-Park." El "Teatro del Petit Park", aunaba el concepto de parque de atracciones, con teatro al aire libre, y mâ”śâ•‘sica en directo. El lugar eran los antiguos terrenos de la Exposiciâ”śâ”‚n Hispano-Francesa de 1908, aâ”śâ•‘n sin urbanizar, al lado de la nueva Plaza de Castelar. En la imagen, uno de los festivales de jota que se celebraban en la ciudad. Al fondo, el Teatro Circo y la chimenea de la central elâ”śÂ®ctrica de ERZ en la calle Isaac Peral esquina con San Miguel. Cuando se completara la urbanizaciâ”śâ”‚n de la zona, este efâ”śÂˇmero Teatro echarâ”śĂ­ el telâ”śâ”‚n.', 1917, 1917, 1917, 'Anos 10', 'CENTRO', 41.64986700, -0.88067600, '0101000020E610000036E84B6F7F2EECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14925205087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14925205087.webp', 'https://www.flickr.com/photos/zaragozaantigua/14925205087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23963, 'De entre los muertos 1959', 'Eficaz anuncio ambulante de la pelâ”śÂˇcula Vâ”śÂ®rtigo (1958) de Alfred Hitchcock. Coche fâ”śâ•‘nebre aparcado en el paseo de la Independencia, frente al Cine Alhambra, donde se proyecta desde hace ya 11 semanas, segâ”śâ•‘n reza el cartel de la izquierda. Fuente: Colecciâ”śâ”‚n GOG.', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65050700, -0.88256600, '0101000020E61000001AF8510DFB3DECBFD76839D043D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14940504556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14940504556.webp', 'https://www.flickr.com/photos/zaragozaantigua/14940504556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23964, 'Teatro Circo 1960', 'Ayuntamiento de Zaragoza/Gerardo Sancho, 1960. El Teatro Circo estaba situado en la esquina de la calle San Miguel con Isaac Peral, donde hoy hay un estanco. Estuvo en pie de 1887 hasta 1961.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65079100, -0.88036900, '0101000020E6100000F030ED9BFB2BECBFFCC3961E4DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14982614255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14982614255.webp', 'https://www.flickr.com/photos/zaragozaantigua/14982614255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23997, 'Paseo Independencia 1959', 'Aspecto parcial de la comparsa publicitaria del Circo Espaâ”śâ–’ol, en las fiestas del Pilar de 1959. Al fondo, la tienda de fotografâ”śÂˇa de Miguel Marâ”śÂˇn Chivite, en el entonces nâ”śâ•‘mero 12 del paseo de la Independencia. Fuente: www.todocoleccion.net', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65089300, -0.88241400, '0101000020E61000009A0AF148BC3CECBF01193A7650D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21026706684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21026706684.webp', 'https://www.flickr.com/photos/zaragozaantigua/21026706684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24016, 'Paseo Independencia 2001', 'El Colectivo Pedalea nace en la Universidad de Zaragoza en septiembre de 1990, recogiendo iniciativas anteriores de reivindicaciâ”śâ”‚n de la bicicleta como transporte urbano, como las de la Asamblea Ecologista. Desde 2001 organiza una Marcha Ciclonudista anual, para visibilizar este modelo de desplazamiento y solicitar mayor atenciâ”śâ”‚n por parte de la Administraciâ”śâ”‚n. En 2015, el Ayuntamiento de Zaragoza concediâ”śâ”‚ el tâ”śÂˇtulo de Hijo Predilecto a esta asociaciâ”śâ”‚n. En la foto, primera Marcha Ciclonudista, el 14 de junio de 2001 en el paseo de la Independencia. Tras los ciclistas, la acera de los impares. Fuente: Agencia EFE.', 2001, 2001, 2001, 'Siglo XXI', 'CENTRO', 41.65028300, -0.88272600, '0101000020E61000005186AA984A3FECBF88122D793CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24356130090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24356130090.webp', 'https://www.flickr.com/photos/zaragozaantigua/24356130090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24037, 'P.â”¬â•‘ de la Independencia 1931', 'Domingo, 29 de marzo de 1931, paseo de la Independencia. Manifestaciâ”śâ”‚n pro amnistâ”śÂˇa organizada por el Partido Republicano Radical Socialista, previamente autorizada por el gobernador civil. Fuente visual: www.facebook.com/photo.php?fbid=10208274413570623&set...', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64978900, -0.88356600, '0101000020E6100000EF703B342C46ECBF782634492CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30139127726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30139127726.webp', 'https://www.flickr.com/photos/zaragozaantigua/30139127726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24068, 'Teatro Circo 1960', 'Imagen interior del peculiar Teatro Circo, construido en 1887 sobre unos antiguos lavaderos esquineros entre la calle de los Sitios, y la de San Miguel, teniendo por trasera la enorme huerta del convento de Jerusalâ”śÂ®n. A lo largo de su vida al servicio del espectâ”śĂ­culo, fue objeto de numerosas reformas y modificaciones, hasta resultar en esta imagen, en sus â”śâ•‘ltimos tiempos de funcionalidad. Estuvo activo hasta 1961, y fue derribado al aâ”śâ–’o siguiente. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65079900, -0.88038500, '0101000020E61000005C72DC291D2CECBF7FA2B2614DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33902070272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33902070272.webp', 'https://www.flickr.com/photos/zaragozaantigua/33902070272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24083, 'Fiesta de la Flor 1916', 'Foto: Sâ”śĂ­nchez Româ”śĂ­n. Puesto de recaudaciâ”śâ”‚n durante la Fiesta de la Flor, instalado en la plaza de Santa Engracia. Detrâ”śĂ­s, valla perimetral del Teatro Pignatelli. Fuente: Revista Blanco y Negro, 21-5-1916.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.64941500, -0.88343300, '0101000020E61000001FA166481545ECBF1344DD0720D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42703308505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42703308505.webp', 'https://www.flickr.com/photos/zaragozaantigua/42703308505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24108, 'Calle de San Miguel 1937', 'Imagen capturada en el Teatro Circo durante el transcurso del festival del Auxilio de Invierno organizado el 17 de marzo de 1937 por Falange. En el engalanado escenario, decorado con los retratos del "Generalâ”śÂˇsimo" Franco y de Josâ”śÂ® Antonio Primo de Rivera (en la imagen), ademâ”śĂ­s de con las banderas de Falange y de la Espaâ”śâ–’a nacionalista, figura junto a un piano el gran tenor Miguel Fleta ataviado con el uniforme de falangista, durante su actuaciâ”śâ”‚n programada, que culminâ”śâ”‚ cantando con el brazo en alto el Himno de Falange, tras el que profiriâ”śâ”‚ los "gritos reglamentarios" ("Arriba Espaâ”śâ–’a", y etc.) contestados unâ”śĂ­nimemente por el enfervorizado pâ”śâ•‘blico asistente.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65077300, -0.88045100, '0101000020E610000039605793A72CECBF560F98874CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51817689172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51817689172.webp', 'https://www.flickr.com/photos/zaragozaantigua/51817689172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24111, 'Paseo de la Independencia 1918', 'Ceremonia de la jura de bandera de los reclutas del servicio militar obligatorio de tres aâ”śâ–’os, el 2 de marzo de 1918 en el paseo de la Independencia. Al fondo, el quiosco de la mâ”śâ•‘sica y la plaza de la Constituciâ”śâ”‚n.', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65042000, -0.88277900, '0101000020E6100000060FD3BEB93FECBF08556AF640D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52021750525.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52021750525.webp', 'https://www.flickr.com/photos/zaragozaantigua/52021750525/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24116, 'P.â”¬â•‘ de la Independencia 1917', 'Imagen capturada desde la altura del Monumento al Justiciazgo en la plaza de Aragâ”śâ”‚n con una vista del abarrotado paseo de la Independencia durante el paso de la funeraria comitiva del torero Florentino Ballesteros en su trayecto desde el Hospicio Provincial por algunos câ”śÂ®ntricos viales el dâ”śÂˇa 26 de abril de 1917. Hacia el fondo, el Quiosco de la Mâ”śâ•‘sica en su temporal emplazamiento en el bulevar del paseo. El fâ”śÂ®retro, en la parte superior de la escena, aparece conducido a hombros por los toreros de la ciudad, que en la plaza de la Constituciâ”śâ”‚n tomaron el relevo a los asilados del Hospicio. Tras ellos, el alcalde, Gumersindo Claramunt Pastor, el presidente de la Diputaciâ”śâ”‚n provincial, Enrique Isabal Pallarâ”śÂ®s, una numerosa Comisiâ”śâ”‚n de diputados en Cortes y varios jefes y oficiales militares, concejales, periodistas. La banda de mâ”śâ•‘sica del Hospicio interpretâ”śâ”‚ durante el recorrido algunas marchas fâ”śâ•‘nebres. Tras el pâ”śâ•‘blico en general, un buen nâ”śâ•‘mero de coches, algunos de los cuales transportaban las coronas de flores. Poco despuâ”śÂ®s y a la altura de la Facultad de Medicina y Ciencias, el canto de un responso marcâ”śâ”‚ el final de trayecto del cortejo y duelo pâ”śâ•‘blico. El fâ”śÂ®retro fue depositado en un carruaje que lo condujo inmediatamente al cementerio catâ”śâ”‚lico de Torrero, donde fue inhumado.', 1917, 1917, 1917, 'Anos 10', 'CENTRO', 41.65042000, -0.88277900, '0101000020E6100000060FD3BEB93FECBF08556AF640D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52248960354.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52248960354.webp', 'https://www.flickr.com/photos/zaragozaantigua/52248960354/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24128, 'P.â”¬â•‘ de la Indepedencia 1916', 'Fotograma de un reportaje dedicado a la ceremonia de "jura de banderas" de los reclutas de la guarniciâ”śâ”‚n celebrada el dâ”śÂˇa 5 de marzo de ese aâ”śâ–’o en el paseo de la Independencia. En un dâ”śÂˇa de cierzo furioso, el acto se iniciâ”śâ”‚ con una ceremonia religiosa oficiada en el Quiosco de la Mâ”śâ•‘sica y finalizâ”śâ”‚ con desfiles militares en el paseo de Pamplona. Esa jornada hubo rancho "extraordinario" para la tropa y permiso para asistir luego a los "espectâ”śĂ­culos pâ”śâ•‘blicos". En la imagen, â”śâ”‚sculo de un recluta al estandarte de su Cuerpo. En la prensa de la â”śÂ®poca, al hilo de este evento, se afirmaba que "Si vosotros (los nuevos reclutas) depositâ”śĂ­is vuestra fe y vuestra confianza en las virtudes de quienes os mandan, no lo dudâ”śÂ®is, encontrarâ”śÂ®is abierto y fâ”śĂ­cil el camino de la gloria". Esa misma gloria la estaban alcanzando, en ese mismo momento, las tropas francesas y alemanas enfrentadas por el control de las colinas fortificadas de Verdâ”śâ•‘n en el marco de la Gran Guerra. Habrâ”śÂˇa gloria para dar y tomar: se estima que esta batalla ocasionâ”śâ”‚ un millâ”śâ”‚n de bajas entre ambos bandos en los diez meses que durâ”śâ”‚. Esa misma gloria fue rodada por Stanley Kubrick en el filme "Paths of glory" (1957), ambientada en el frente francâ”śÂ®s durante el aâ”śâ–’o 1916. Tal vez por hacerlo tan certeramente esta pelâ”śÂˇcula no pudo ser estrenada en Zaragoza hasta 1986.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.65058900, -0.88251100, '0101000020E610000038876BB5873DECBF9411178046D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54734766556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54734766556.webp', 'https://www.flickr.com/photos/zaragozaantigua/54734766556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24134, 'Petit Park c.1917', 'Imagen del "Teatro del Petit Park" en una zona de las antiguas instalaciones de la Exposiciâ”śâ”‚n Hispano-Francesa de 1908, en lo que fuera huerta de Santa Engracia, entonces plaza de Castelar. Tras el desmantelamiento de la mayor parte de los efâ”śÂˇmeros componentes de la Expo, y hasta que la urbanizaciâ”śâ”‚n de la zona vaya progresando, este Teatro serâ”śĂ­ un curioso espacio de entretenimiento, con espectâ”śĂ­culos variados. En esta imagen, una irrepetible visual de la ciudad. De izquierda a derecha, las huertas del convento de Jerusalâ”śÂ®n y la enorme chimenea de la central de la "Electra Peral Zaragozana", en la esquina de la calle San Miguel con la de los Sitios. A su derecha, las traseras del "Teatro Circo". Al fondo, el remate de la torre de la Seo. A continuaciâ”śâ”‚n, las traseras de los actuales nâ”śâ•‘meros 14, 16 y 18 de viviendas de la calle San Miguel, levantados en la dâ”śÂ®cada de los ochenta del siglo XIX. Por encima de ellos sobresale la chimenea de la otra central electrica que habâ”śÂˇa entre las calles de Blancas y Porcell. En el centro, el convento de Santa Catalina. A la derecha, la torre de la iglesia de San Miguel. Esta descripciâ”śâ”‚n ha tenido su utilidad en la comunicaciâ”śâ”‚n "Instantâ”śĂ­neas de un â”¬Â˝Paraâ”śÂˇso de recreoâ”¬â•— en Zaragoza: el desaparecido Petit Park Ă”Ă‡Ă´luego Saturno ParkĂ”Ă‡Ă´ (1920-1925)", firmada por Mâ”śâ”‚nica Vâ”śĂ­zquez Astorga y Rebeca Carretero Calvo, incluida en "II Jornadas sobre Investigaciâ”śâ”‚n en Historia de la Fotografâ”śÂˇa. 1839-1939: Un siglo de fotografâ”śÂˇa", Hernâ”śĂ­ndez Latas, Josâ”śÂ® Antonio (ed.), IFC, 2018. Fuente visual: panorâ”śĂ­mica posiblemente realizada sobre la base de tres postales editadas por Lucas Escolâ”śĂ­ en la serie titulada "PETIT-PARC PRO-INFANCIA. ZARAGOZA", Colecciâ”śâ”‚n Gerardo Alcaâ”śâ–’iz, en "El libro de oro de Aragâ”śâ”‚n", EPA, 1997.', 1917, 1917, 1917, 'Anos 10', 'CENTRO', 41.64986700, -0.88067600, '0101000020E610000036E84B6F7F2EECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19198805050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19198805050.webp', 'https://www.flickr.com/photos/zaragozaantigua/19198805050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24280, 'Puerta de Santa Engracia 1737', '"Primera Puerta de Santa Engracia", Antonio Callaved, 2010. Construida junto al monasterio de Santa Engracia, fue derruida en los sitios. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1737, 1737, 1737, 'Siglo XIX', 'CENTRO', 41.64940100, -0.88334700, '0101000020E61000007BA180ED6044ECBFAE7E6C921FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15093271329.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15093271329.webp', 'https://www.flickr.com/photos/zaragozaantigua/15093271329/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24295, 'Calle Sanclemente 1980', 'La especulaciâ”śâ”‚n inmobiliaria en Zaragoza no es una plaga bâ”śÂˇblica, ni una pena tristosa cuyo objetivo es afear la belleza natural de la preciosa ciudad en que vivimos. "Sigue al dinero" aconsejan en las pelis que tratan de la corrupciâ”śâ”‚n y la especulaciâ”śâ”‚n, y no les falta razâ”śâ”‚n: junto a la "liberaciâ”śâ”‚n" de enormes cantidades de suelo urbano en el precioso centro de la ciudad, la especulaciâ”śâ”‚n inmobiliaria en Zaragoza lleva asociado el piqueteo de industrias ("Carde y Escoriaza", "Mercier", "Lanera Aragonesa", "Textil Pina", "Alumalsa"...), conventos (las Fecetas, Santa Inâ”śÂ®s, Santa Lucâ”śÂˇa, las Adoratrices, Altabâ”śĂ­s...), colegios confesionales (Sagrado Corazâ”śâ”‚n, El Salvador, Carmelitas, Santa Ana, La Salle Montemolâ”śÂˇn, Teresianas...), de forma que el aroma monetario, la "grasa" que engrasa los mecanismos de este proceso, nos conduce a las grandes fortunas asociadas al autâ”śÂ®ntico "monopoly" que se juega en la ciudad. La triste pâ”śÂ®rdida de edificios de factura que merecerâ”śÂˇa su preservaciâ”śâ”‚n, sâ”śâ”‚lo es la epidermis, la fachada, de un asunto que hunde sus raâ”śÂˇces en la trama de poder y las redes polâ”śÂˇticas y econâ”śâ”‚micas que manejan el cotarro zaragozano, en un escenario no muy sustancialmente diferente antes y despuâ”śÂ®s de la autoproclamada "transiciâ”śâ”‚n". En la imagen, chaflâ”śĂ­n de las calles Sanclemente-Isaac Peral donde una apuntada puerta en formas neogâ”śâ”‚ticas (aquâ”śÂˇ eclipsada por un cartelâ”śâ”‚n publicitario) seâ”śâ–’alaba el acceso al antiguo Colegio Teresiano Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, de la Compaâ”śâ–’â”śÂˇa de Santa Teresa de Jesâ”śâ•‘s, ideado por Teodoro Râ”śÂˇos Balaguer y activo en esta ubicaciâ”śâ”‚n desde 1926. Este colegio ocupaba un buen bocado, en lo mâ”śĂ­s granado del "centro". La desventurada historia del solar es prolija: pasâ”śâ”‚ por varias manos como las tarjetas de propiedad del "monopoly". El momento de la captura de la imagen ilustra un espacio de tiempo de los denominados "barbecho expectante", a la espera de un reajuste de ofertas. Finalmente, el edificio fue piqueteado, y sobre â”śÂ®l se levantâ”śâ”‚ el cementoso y compacto ', 1980, 1980, 1980, 'Anos 80', 'CENTRO', 41.64970700, -0.88103000, '0101000020E6100000A86F99D36531ECBFBB7D569929D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16315237291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16315237291.webp', 'https://www.flickr.com/photos/zaragozaantigua/16315237291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24301, 'Pl. de Santa Engracia 1927', 'Dibujo de Ambrosio Ruste que representa la zona de escaleras de acceso de la plaza de Santa Engracia al paseo de la Independencia de Zaragoza, la casa Pamplona Escudero (a la derecha), luego derribada. Al fondo, el edificio del nâ”śâ•‘mero 30 del paseo de la Independencia. Fuente: â”¬Ă­Aquâ”śÂˇ... Zaragoza!, Josâ”śÂ® Blasco Ijazo, 1952.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64955400, -0.88348000, '0101000020E61000004C7155D97745ECBF357EE19524D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19212269103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19212269103.webp', 'https://www.flickr.com/photos/zaragozaantigua/19212269103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24306, 'Victoria Eugenia 1908', 'Foto: Ignacio Coyne, 1908. "Inauguraciâ”śâ”‚n de la Exposiciâ”śâ”‚n Hispano Francesa". En el centro, la reina Victoria Eugenia. Tras ella, el rey Alfonso XIII. Detrâ”śĂ­s, la iglesia de Santa Engracia, el Pabellâ”śâ”‚n de Francia y el Quiosco de la Mâ”śâ•‘sica. La inauguraciâ”śâ”‚n de la Exposiciâ”śâ”‚n Hispano Francesa de Zaragoza ya habâ”śÂˇa tenido lugar. Los reyes inauguraron el Monumento a los Sitios. Fuente: dara.aragon.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64967500, -0.88057900, '0101000020E6100000986BD102B42DECBFB003E78C28D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19606723055.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19606723055.webp', 'https://www.flickr.com/photos/zaragozaantigua/19606723055/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24307, 'Ilusiorama 1908', 'En la zona prâ”śâ”‚xima al Pabellâ”śâ”‚n Francâ”śÂ®s de la Exposiciâ”śâ”‚n Hispano Francesa de Zaragoza, se hallaba la zona denominada Parque de Atracciones, que sobrevivirâ”śĂ­ a la muestra con el nombre de Petit Park. Incluâ”śÂˇa tiro al blanco, barcas voladoras, el hilo de amor, cinematâ”śâ”‚grafo, tobogâ”śĂ­n e ilusiorama. Este â”śâ•‘ltimo contaba con patio de butacas y proyecciâ”śâ”‚n de cine multiplicada por espejos, que rodeaban al espectador, simultâ”śĂ­neamente a la actuaciâ”śâ”‚n de bailarinas del Teatro Real de Madrid con mâ”śâ•‘sica en directo y efectos luminosos mediante 2000 lâ”śĂ­mparas. Fuente visual: "Secciâ”śâ”‚n de Espectâ”śĂ­culos. Ilusiorama", foto Ignacio Coynâ”śÂ®, en "â”śĂĽlbum oficial descriptivo Exposiciâ”śâ”‚n Hispano-Francesa 1908.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64986700, -0.88067600, '0101000020E610000036E84B6F7F2EECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19615613015.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19615613015.webp', 'https://www.flickr.com/photos/zaragozaantigua/19615613015/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24314, 'Calle Zurita 1976', 'En la imagen, chaflâ”śĂ­n de la entrada principal al Colegio Teresiano del Pilar desde la calle Zurita 12. Destaca el recrecimiento vertical aâ”śâ–’adido a la traza original que Teodoro Râ”śÂˇos Balaguer diseâ”śâ–’â”śâ”‚ en 1925 La calle Isaac Peral cruza Zurita y, al fondo a la izquierda, la Escuelas de Artes Aplicadas y Oficios Artâ”śÂˇsticos, en la plaza de Josâ”śÂ® Antonio. Fuente: aportaciâ”śâ”‚n de Elena de Salas, Directora General, y Presidenta del Consejo Escolar, del Colegio Teresiano del Pilar.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65008600, -0.88093200, '0101000020E6100000F4FE3F4E9830ECBF32CB9E0436D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22858749517.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22858749517.webp', 'https://www.flickr.com/photos/zaragozaantigua/22858749517/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24315, 'Calle Sanclemente 1976', 'Como los pisos del 19 de la calle del Pilar se les habâ”śÂˇan quedado chicos, al principio de los aâ”śâ–’os 20 las HH. Teresianas comenzaron a buscar una nueva ubicaciâ”śâ”‚n, mâ”śĂ­s espaciosa, para su colegio, que encontraron en los promisorios terrenos en urbanizaciâ”śâ”‚n de la antigua huerta de Santa Engracia, en el entorno de la nueva plaza de Castelar. Teodoro Râ”śÂˇos Balaguer firmâ”śâ”‚ el diseâ”śâ–’o, en 1925, de la nueva planta del centro (una curiosa combinaciâ”śâ”‚n de aportes neogâ”śâ”‚ticos, mudâ”śÂ®jares, y racionalistas) con provisional direcciâ”śâ”‚n en "calle de los Sitios s/n", aunque la prolongaciâ”śâ”‚n del vial Sanclemente les adjudicâ”śâ”‚ ese nomenclâ”śĂ­tor, con el nâ”śâ•‘mero 15. El curso 1926-27 fue el primero en este emplazamiento del nuevo colegio, que en 1958 fue ampliado en horizontal hasta la calle Zurita, donde se situâ”śâ”‚ la nueva entrada principal, con el nâ”śâ•‘mero 12. En 1960 fue ampliado, esta vez en vertical, para adecuarlo a su nueva funcionalidad como Colegio, Residencia Universitaria, y sede de Comunidad Religiosa. En total, unas 500 personas entre residentes temporales y permanentes. A mediados de los aâ”śâ–’os 70, la nueva Ley General de Educaciâ”śâ”‚n seguâ”śÂˇa sin ser aplicada en lo relativo a las caracterâ”śÂˇsticas requeridas a los centros educativos homologados (mayor superficie â”śâ•‘til por alumno, instalaciones deportivas, servicios de biblioteca, laboratorio, sala de usos mâ”śâ•‘ltiples, sala de profesores...). Este centro no podâ”śÂˇa adaptarse a esos demandas espaciales, (de donde no hay, no se puede sacar), de forma que en 1978 se trasladâ”śâ”‚ a la ultraperiferia de la ciudad (camino de Pinseque, nâ”¬â•‘ 37), donde hoy sigue. Un par de aâ”śâ–’os antes, en 1976, se habâ”śÂˇa celebrado el Centenario I de la fundaciâ”śâ”‚n de la Compaâ”śâ–’â”śÂˇa de Santa Teresa de Jesâ”śâ•‘s, por Enrique de Ossâ”śâ”‚ y Cervellâ”śâ”‚. El edificio abandonado entrâ”śâ”‚ en la habitual espiral especulativa propia de aquellos aâ”śâ–’os. Y de los siguientes. En la imagen, chaflâ”śĂ­n de entrada al Colegio Teresiano del Pilar desde la calle de Felipe Sanclemente. A la izquierda, la de Isaac Peral, y al fon', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64970700, -0.88103000, '0101000020E6100000A86F99D36531ECBFBB7D569929D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23110592862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23110592862.webp', 'https://www.flickr.com/photos/zaragozaantigua/23110592862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24319, 'Exposiciâ”śâ”‚n de 1908', 'Imagen capturada en el interior del recinto de la Exposiciâ”śâ”‚n Hispano-Francesa de 1908 y centrada en el Quiosco para mâ”śâ•‘sica diseâ”śâ–’ado por los hermanos Josâ”śÂ® y Manuel Martâ”śÂˇnez de Ubago y Lizâ”śĂ­rraga, y el espacio habilitado alrededor para pâ”śâ•‘blico asistente. Tras el quiosco, instalaciâ”śâ”‚n de jardinerâ”śÂˇa y arboricultura francesas y fachada principal del Pabellâ”śâ”‚n francâ”śÂ®s o de los franceses, proyectado por Joseph-Charles de Guirard de Montarnal y encargado de su construcciâ”śâ”‚n Fâ”śÂ®lix Navarro Pâ”śÂ®rez. A la derecha, vista parcial del Parque de atracciones habilitado en la muestra. Al fondo, edificios de las calles de Zurita y Huertas. Fuente visual: Archivo fotogrâ”śĂ­fico histâ”śâ”‚rico del SIPA, en AHPZ.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64942800, -0.88042800, '0101000020E61000002E724F57772CECBFA88DEA7420D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31240611188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31240611188.webp', 'https://www.flickr.com/photos/zaragozaantigua/31240611188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24323, 'Minas 1809', '"Plano parcial de Zaragoza usado por los franceses, y en el que se ven seâ”śâ–’alados los lugares donde se colocaron los hornillos de pâ”śâ”‚lvora". Fotografâ”śÂˇa de 1950. Guerra de minas en el segundo sitio de Zaragoza (1809). Abarca desde el Coso (al norte) hasta la huerta de Santa Engracia. Fuente: Museo del Ejâ”śÂ®rcito.', 1809, 1809, 1809, 'Siglo XIX', 'CENTRO', 41.64940700, -0.88201900, '0101000020E6100000836BEEE87F39ECBF9065C1C41FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31913436763.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31913436763.webp', 'https://www.flickr.com/photos/zaragozaantigua/31913436763/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24371, 'Gran Hotel 1966', 'Imagen del Gran Hotel, chaflâ”śĂ­n calle Costa-Isaac Peral, con aspecto parcial, al fondo a la izquierda, del Colegio Teresiano Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, de la Compaâ”śâ–’â”śÂˇa de Santa Teresa de Jesâ”śâ•‘s, en esa ubicaciâ”śâ”‚n desde 1926. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64970700, -0.88103000, '0101000020E6100000A86F99D36531ECBFBB7D569929D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15597066558.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15597066558.webp', 'https://www.flickr.com/photos/zaragozaantigua/15597066558/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24421, 'Calle de Câ”śĂ­diz c.1925', 'Imagen capturada en altura desde las traseras de la calle Casa Jimâ”śÂ®nez, y centrada en la huerta del colegio de las Reverendas Hermanas Carmelitas de la Tercera Orden o Terciarias sito en la calle de Câ”śĂ­diz nâ”¬â•‘ 2, heredero de la que fuera antigua Casa de las Recogidas, y editada como parte de una colecciâ”śâ”‚n de postales publicitarias realizadas por el estudio de fotografâ”śÂˇa Machetti, sito en el piso principal del nâ”¬â•‘ 27 del Coso Alto. Al comienzo de la dâ”śÂ®cada de los 70 del pasado siglo XX este colegio estaba gestionado por Carmelitas Misioneras Teresianas que en 1977 lo vendieron para costearse unas nuevas y lejanas instalaciones en el barrio de Casablanca. El antiguo edificio colegial, incluyendo la neoclâ”śĂ­sica iglesia de su interior, fue derribado al poco tiempo para levantar sobre su solar una pionera y moderna gran superficie comercial. Al fondo, y emergentes sobre el entorno de la calle del Laurel, las dos primeras torres del Templo Metropolitano del Pilar. Fuente visual: www.todocoleccion.net/', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65071900, -0.88402200, '0101000020E610000071395E81E849ECBF63F19BC24AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35632572195.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35632572195.webp', 'https://www.flickr.com/photos/zaragozaantigua/35632572195/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25065, 'Miguel Fleta 1925', '"Zaragoza, 7 de junio de 1925. Festival a beneficio de la Asociaciâ”śâ”‚n de la Prensa en el Teatro Circo de Zaragoza. En el centro: Miguel Fleta. A su derecha: Alejandro Castejâ”śâ”‚n Gay, Jefe de Tramoya del citado Teatro Circo. Primero por la izquierda, con traje claro, chalina y luto en la solapa (al estilo de la â”śÂ®poca): Mariano Gimeno, sobrino del famoso Eduardo Gimeno, autor de la pelâ”śÂˇcula Salida de Misa de 12 del Pilar de Zaragoza." Fuente: rafaelcastillejo.com', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65086800, -0.88044100, '0101000020E610000056D7A19A922CECBFA80183A44FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15004235812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15004235812.webp', 'https://www.flickr.com/photos/zaragozaantigua/15004235812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25137, 'Edificio Ambos Mundos 1945', 'Dibujo publicitario del edificio levantado en el nâ”śâ•‘mero 30 del paseo de la Independencia de Zaragoza (hoy 32 y 34). Albergaba el cafâ”śÂ® Ambos Mundos en sus bajos desde 1881, cuando fue comprado por el Banco de Crâ”śÂ®dito de Zaragoza, fundado en 1845. En 1947, esta entidad fue absorbida por el Banco Central. El 2 de septiembre de 1955, cerrâ”śâ”‚ el cafâ”śÂ®. Hoy, esta casa estâ”śĂ­ despojada de su ornamentaciâ”śâ”‚n exterior. Fuente: Revista Aragâ”śâ”‚n, 1945.', 1945, 1945, 1945, 'Anos 40', 'CENTRO', 41.64932200, -0.88425900, '0101000020E61000007F32C687D94BECBF6249B9FB1CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20760836905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20760836905.webp', 'https://www.flickr.com/photos/zaragozaantigua/20760836905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25269, 'Cine Coliseo Equitativa c.1956', 'Foto Gonzalo Bullâ”śâ”‚n. Construido en 1949, con proyecto de Josâ”śÂ® de Yarza y Manuel Martâ”śÂˇnez, la imagen captura el aspecto de su pantalla tras haber sido adaptada en 1955 para la proyecciâ”śâ”‚n en sistema "cinemascope". Reconvertido en gran superficie comercial de ropa, conserva a la vista la techumbre de madera.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65060800, -0.88173800, '0101000020E61000008D7E349C3237ECBF0B42791F47D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14823138138.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14823138138.webp', 'https://www.flickr.com/photos/zaragozaantigua/14823138138/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25272, 'P.â”¬â•‘ de la Independencia 1930', '"Paseo de la Independencia". Sol de invierno, en el tramo entre Casa Jimâ”śÂ®nez, a la izquierda, y la Plaza de la Constituciâ”śâ”‚n, al fondo. Los â”śĂ­rboles del boulevard, plantados hacâ”śÂˇa poco.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64949000, -0.88369100, '0101000020E61000000AA018593247ECBF1E8A027D22D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14955532288.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14955532288.webp', 'https://www.flickr.com/photos/zaragozaantigua/14955532288/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25274, '8 de marzo de 1936', 'Jornada Internacional de la Mujer del 8 de marzo de 1936 en Zaragoza. Una de las manifestaciones mâ”śĂ­s multitudinarias convocadas en la ciudad por las fuerzas de izquierda durante la Segunda Repâ”śâ•‘blica espaâ”śâ–’ola, con mâ”śĂ­s de 20.000 participantes. En la imagen, mujeres y hombres participantes en la manifestaciâ”śâ”‚n en el Paseo de la Independencia.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64935400, -0.88384100, '0101000020E61000005DA5BBEB6C48ECBF6EC328081ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14980402266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14980402266.webp', 'https://www.flickr.com/photos/zaragozaantigua/14980402266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25276, '8 de marzo de 1936', 'AHPZ. Archivo Fotogrâ”śĂ­fico Coyne. Manuel Coyne Buil. 1936. La Jornada Internacional de la Mujer del 8 de marzo de 1936 fue una de las manifestaciones mâ”śĂ­s multitudinarias convocadas por las fuerzas de izquierda zaragozanas durante la Segunda Repâ”śâ•‘blica, con mâ”śĂ­s de 20.000 participantes. Al final del acto los organizadores entregaron al gobernador civil, â”śĂĽngel Vera Coronel, un manifiesto en el que reclamaban "el encarcelamiento de los responsables de la represiâ”śâ”‚n de octubre de 1934 y una indemnizaciâ”śâ”‚n para los familiares de las vâ”śÂˇctimas; trabajo o subsidio para los parados; el abaratamiento de las subsistencias y de los alquileres; la disoluciâ”śâ”‚n y el desarme total de las bandas fascistas; contra la guerra y el fascismo; y por la libertad del pueblo abisinio". En la imagen, la manifestaciâ”śâ”‚n se dirige por el Paseo Independencia hacia la sede del Gobierno Civil en la Plaza de Aragâ”śâ”‚n, y pasa por la esquina con la calle Casa Jimâ”śÂ®nez. Entre la asistencia, la bandera constitucional, seguida de una pancarta de la Juventud Socialista Unificada, como unificaciâ”śâ”‚n de la Uniâ”śâ”‚n de Juventudes Comunistas y las Juventudes Socialistas. Habrâ”śÂˇan de pasar varias dâ”śÂ®cadas para que el 8 de marzo recuperara su carâ”śĂ­cter reivindicativo, feminista, democrâ”śĂ­tico.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64956300, -0.88380900, '0101000020E61000008522DDCF2948ECBF88D860E124D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15000151371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15000151371.webp', 'https://www.flickr.com/photos/zaragozaantigua/15000151371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25279, 'P.â”¬â•‘ de la Independencia 1956', 'Foto Josâ”śÂ® Antonio Duce, 1956. Vista desde el boulevard central del paseo de la Independencia, hacia la plaza Aragâ”śâ”‚n. Operarios municipales riegan el firme. A la izquierda, edificio de Correos (1926). Fuente: www.gozazaragoza.com/contenido.php?id=9720 a travâ”śÂ®s de www.facebook.com/photo.php?fbid=370948889728613&set=o...', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.64936000, -0.88377200, '0101000020E61000003CDBA337DC47ECBF50AA7D3A1ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15088170904.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15088170904.webp', 'https://www.flickr.com/photos/zaragozaantigua/15088170904/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25280, 'P.â”¬â•‘ de la Independencia 1928', 'Acera de los pares del paseo de la Independencia en 1928, hacia la plaza de Aragâ”śâ”‚n. Al fondo, edificio en reformas del nâ”śâ•‘mero 32-34, entre las calles Casa Jimâ”śÂ®nez y Albareda, enfrente del edificio de Telefâ”śâ”‚nica. Fuente: rt000z8y.eresmas.net/', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.65020200, -0.88307600, '0101000020E6100000683D7C992842ECBF9BE5B2D139D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15222825257.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15222825257.webp', 'https://www.flickr.com/photos/zaragozaantigua/15222825257/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25283, 'La cabra de la Legiâ”śâ”‚n 1982', 'Paso del Desfile del Dâ”śÂˇa de las Fuerzas Armadas por el paseo de la Independencia de Zaragoza en 1982. Al fondo, la plaza de Espaâ”śâ–’a. En el centro de la imagen, la cabra de la Legiâ”śâ”‚n, mascota de esta fuerza militar necrâ”śâ”‚fila creada en 1920 por Josâ”śÂ® Millâ”śĂ­n-Astray. Fuente: www.facebook.com/photo.php?fbid=293499314182209&set=o...', 1982, 1982, 1982, 'Anos 80', 'CENTRO', 41.64972300, -0.88338800, '0101000020E61000001FB935E9B644ECBFC13A8E1F2AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15283766167.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15283766167.webp', 'https://www.flickr.com/photos/zaragozaantigua/15283766167/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25291, 'P.â”¬â•‘ de la Independencia 1956', 'Câ”śÂ®sar Gracia Jarque. 1956. "Paseo de la Independencia."', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15754497980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15754497980.webp', 'https://www.flickr.com/photos/zaragozaantigua/15754497980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25298, 'Tako 1989', 'Foto: Vicente Jorcano para Heraldo de Aragâ”śâ”‚n, 1989. Actuaciâ”śâ”‚n del grupo ejeano de rock urbano Tako, en la sala M-Tro de Zaragoza, durante el concurso Medio Kilo de Rock en 1989. Fueron los ganadores. La sala M-Tro fue un local multidisciplinar, con exposiciones, tiendas de ropa, artesanâ”śÂˇa, libros y discos, peluquerâ”śÂˇa, oficina de fomento de autoempleo y unos bajos para actuaciones y proyecciones, con capacidad para 300 personas. Fue inaugurada en 1986. Fuente: www.facebook.com/zgz80s/photos/a.127459403989874.22917.12...', 1989, 1989, 1989, 'Anos 80', 'CENTRO', 41.64996300, -0.88445300, '0101000020E6100000BB2BBB60704DECBF164ED2FC31D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19269782166.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19269782166.webp', 'https://www.flickr.com/photos/zaragozaantigua/19269782166/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25299, 'Casa Pamplona 1927', 'Paseo Independencia y palacio de La Rosa, Luicien Roisin, 1927. El edificio de la derecha, en el paseo de la Independencia 29 y 31, es el antiguo palacio del barâ”śâ”‚n de La Rosa, que fue Capitanâ”śÂˇa General entre 1867 y 1888. Era conocido como Casa Pamplona por ser su propietaria la familia Pamplona Escudero. Entre 1904 y 1910, los Hermanos Corazonistas ocuparon parte de sus dependencias. Luis Buâ”śâ–’uel viviâ”śâ”‚ allâ”śÂˇ entre 1906 y 1917. Derribado en 1927, ocupan su solar las casas de Bruned (29, Heraldo de Aragâ”śâ”‚n) y Escoriaza (31, esquina con la plaza de Santa Engracia). A la derecha, ebanisterâ”śÂˇa junto a las escaleras de acceso a la plaza. Fuente: "Zaragoza, aâ”śâ–’os veinte. 81 fotografâ”śÂˇas de Roisin (1925-1931)", Instituciâ”śâ”‚n Fernando el Catâ”śâ”‚lico, 2014.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20085029682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20085029682.webp', 'https://www.flickr.com/photos/zaragozaantigua/20085029682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25305, 'Correos 1936', 'Foto: Miguel Marâ”śÂˇn Chivite. Cuerpo de Carabineros a las puertas de Correos, en el paseo de la Independencia de Zaragoza, durante el intento de golpe de estado de julio de 1936. Fuente: Heraldo de Aragâ”śâ”‚n.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64936000, -0.88377200, '0101000020E61000003CDBA337DC47ECBF50AA7D3A1ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20684498300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20684498300.webp', 'https://www.flickr.com/photos/zaragozaantigua/20684498300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25307, 'P.â”¬â•‘ de la Independencia 1914', 'Manifestaciâ”śâ”‚n de apoyo a los remolacheros convocada la tarde del 6 de marzo de 1914 y con recorrido desde la plaza del Pilar hasta la plaza de Aragâ”śâ”‚n, sede del Gobierno civil. Tambiâ”śÂ®n se reivindicâ”śâ”‚ la apertura del ferrocarril de Canfranc, vieja aspiraciâ”śâ”‚n del gremio desde 1882, la construcciâ”śâ”‚n del ferrocarril de Caminreal y los riegos del Alto Aragâ”śâ”‚n. La imagen se ha capturado desde la altura del Quiosco de la mâ”śâ•‘sica sito en el paseo de la Independencia con una buena vista en profundidad del mismo hasta la plaza de la Constituciâ”śâ”‚n, al fondo.', 1914, 1914, 1914, 'Anos 10', 'CENTRO', 41.64964800, -0.88356400, '0101000020E6100000C2887D022846ECBFB6F468AA27D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21132643409.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21132643409.webp', 'https://www.flickr.com/photos/zaragozaantigua/21132643409/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25309, 'Tanques republicanos 1936', 'En abril de 1936, se celebraron festejos para conmemorar el quinto aniversario de la proclamaciâ”śâ”‚n de la Repâ”śâ•‘blica. En la imagen, tanques desfilando ante el nâ”śâ•‘mero 29 del paseo de la Independencia. En unos pocos meses... Fuente: Archivo Heraldo de Aragâ”śâ”‚n.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21653570888.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21653570888.webp', 'https://www.flickr.com/photos/zaragozaantigua/21653570888/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
