INSERT INTO public.photos VALUES (25321, 'Paseo Independencia c.1955', 'El paseo de la Independencia en el tramo de los edificios desde el nâ”¬â•‘ 31 y 29, a la derecha, diseâ”śâ–’ados respectivamente por Miguel â”śĂĽngel Navarro Pâ”śÂ®rez y por Teodoro Râ”śÂˇos Balaguer, sobre la antigua gran casa del conde de la Rosa que a finales del siglo XIX acogiâ”śâ”‚ provisionalmente la sede la Capitanâ”śÂˇa General. A continuaciâ”śâ”‚n, el singular inmueble conocido como casa Zapatero, situado entre las calles del Cardenal Garcâ”śÂˇa Gil y de Felipe Sanclemente y que aâ”śâ–’os mâ”śĂ­s tarde serâ”śÂˇa objeto de una moderna remodelaciâ”śâ”‚n. Despuâ”śÂ®s, el gran edificio de viviendas de los nâ”śâ•‘meros 23-25 diseâ”śâ–’ado por Teodoro Râ”śÂˇos Balaguer, y finalmente los bloques de viviendas del nâ”¬â•‘ 21 y el edificio del nâ”¬â•‘ 19 donde estaba radicada la sede de la Compaâ”śâ–’â”śÂˇa de Seguros La Equitativa, ambos construidos recientemente sobre el antiguo convento de Jerusalâ”śÂ®n. Fuente visual: www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65002300, -0.88296300, '0101000020E61000005F7F129F3B41ECBFEB5223F433D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23483984999.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23483984999.webp', 'https://www.flickr.com/photos/zaragozaantigua/23483984999/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25322, 'Cine Avenida 1968', 'Dibujo del acceso al cine Avenida, en el paseo de la Independencia 26. En su lugar habâ”śÂˇa estado el cine Alhambra entre 1911 y 1965. Fue inaugurado el 11 de mayo de 1968 segâ”śâ•‘n proyecto de Enrique Bas, y clausurado en enero de 1979 a la vez que el cine Actualidades. Fuente: www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65023600, -0.88341200, '0101000020E6100000419B1C3EE944ECBF4757E9EE3AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23641795301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23641795301.webp', 'https://www.flickr.com/photos/zaragozaantigua/23641795301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
